import React, { useState } from 'react';

const links = [
  { label: 'Home',       href: '#Introduction' },
  { label: 'About Me',   href: '#About-Me' },
  { label: 'Education',  href: '#Education' },
  { label: 'Experience', href: '#Experience' },
  { label: 'Skills',     href: '#Skills' },
  { label: 'My Projects',href: '#Projects' },
  { label: 'Contact',    href: '#Contact' },
];

/* PS button symbols cycling per nav item */
const PS_SYMBOLS = ['✕', '○', '□', '△'];

const Navbar = () => {
  const [hovered, setHovered] = useState(null);

  return (
    <nav
      id="navbar"
      className="fixed top-0 left-0 w-full z-50 flex flex-wrap gap-6 px-6 py-4 shadow-lg"
      style={{
        background: 'linear-gradient(90deg, #00052b 0%, #003791 50%, #00052b 100%)',
        borderBottom: '1px solid rgba(0,112,204,0.5)',
      }}
    >
      {/* PS logo mark */}
      <span
        className="font-bold text-base mr-2 hidden md:inline-block"
        style={{ color: 'rgba(255,255,255,0.25)', letterSpacing: '4px', fontSize: '12px' }}
      >
        ✕&nbsp;○&nbsp;□&nbsp;△
      </span>

      {links.map((link, idx) => {
        const symbol = PS_SYMBOLS[idx % 4];
        const symbolColors = ['#7fc5e8', '#e87b7b', '#e87bce', '#7be8b4'];
        const symbolColor = symbolColors[idx % 4];
        const isHovered = hovered === link.href;

        return (
          <a
            key={link.href}
            href={link.href}
            onMouseEnter={() => setHovered(link.href)}
            onMouseLeave={() => setHovered(null)}
            className="font-bold text-sm no-underline transition-all duration-300 inline-flex items-center gap-1"
            style={{
              color: isHovered ? '#ffffff' : 'rgba(255,255,255,0.75)',
              transform: isHovered ? 'translateY(-2px)' : 'translateY(0)',
              textDecoration: 'none',
              textShadow: isHovered ? `0 0 10px ${symbolColor}` : 'none',
            }}
          >
            <span style={{ color: symbolColor, fontSize: '10px', opacity: isHovered ? 1 : 0.5 }}>
              {symbol}
            </span>
            {link.label}
          </a>
        );
      })}
    </nav>
  );
};

export default Navbar;
